use std::io::{self, Read};

fn main() -> io::Result<()> {
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf)?;
    let v: Vec<u32> = buf
        .split_ascii_whitespace()
        .map(|x| x.parse().unwrap())
        .collect();
    let (k, mut l) = (v[0], v[1]);

    let mut ans = -1;
    while l % k == 0 {
        l /= k;
        ans += 1;
    }

    if l == 1 {
        println!("YES");
        println!("{}", ans);
    } else {
        println!("NO");
    }

    Ok(())
}
